import React, { useState } from 'react';
import './AddPurchase.css';


const AddPurchase = ({ handleAdd }) => {

  const [newPurchase, setNewPurchase] = useState({
    id: '',
    location: '',
    materialid: '',
    quantity: '',
    price:'',
    vendor:'',
    
  });

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  

  const handleSubmit = (event) => {
    event.preventDefault();
    handleAdd(newPurchase);
    resetForm();
  };

  const resetForm = () => {
    setNewPurchase({
      id: '',
      location: '',
      materialid: '',
      quantity: '',
      price:'',
      vendor:'',
    });
  };

  const vendorOptions = [
    { value: '+', label: '+ Add New Vendor' }, // Add the "+" sign as an option
    ...vendors.map((vendor) => ({ value: vendor.vendorid, label: vendor.name })),
  ];

  const filterOption = (option, inputValue) => {
    if (option.value === '+') {
      return true; // Always show the "+" option
    }
    return option.label.toLowerCase().includes(inputValue.toLowerCase());
  };

  
  
  return (
    <div className="add-purchase-container">
      <h2 className="add-purchase-heading">Add Purchase</h2>
      <form className="add-purchase-form" onSubmit={handleSubmit}>
        <div className="form-row">          
          <div className="form-group">
            <label htmlFor="name">Location:</label>
            <input
              type="text"
              id="location"
              name="location"
              value={newPurchase.location}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="materialid">Material ID:</label>
            <input
              type="text" 
              id="materialid"
              name="materialid"
              value={newPurchase.materialid}
              onChange={handleInputChange}
              required
            />
          </div>
          
          <div className="form-group">
            <label htmlFor="quantity">Quantity:</label>
            <input
              type="text"
              id="quantity"
              name="quantity"
              value={newPurchase.quantity}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="price">Price:</label>
            <input
              type="number" 
              id="price"
              name="price"
              value={newPurchase.price}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="vendor" className="vendor-label">
              Vendor:
            </label>
            <Select
              id="vendor"
              name="recent_vendor"
              value={newMaterial.recent_vendor}
              onChange={handleVendorChange}
              options={vendorOptions}
              isClearable={true}
              placeholder="Select a vendor"
              required
              filterOption={filterOption} // Exclude the "+" option from filtering
            />
        </div>
          
        
        </div>
        <button type="submit" className="add-purchase-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default AddPurchase;
